def solution(limit: int = 1000) -> str:
    """
    Returns the last 10 digits of the series 1^1 + 2^2 + ... + n^n.
    """
    total = 0
    # We only need the last 10 digits, so we can use modulo 10^10
    MOD = 10**10

    for i in range(1, limit + 1):
        # Use modular exponentiation for efficiency and to avoid giant numbers
        total = (total + pow(i, i, MOD)) % MOD

    return str(total).zfill(10)


if __name__ == "__main__":
    print(solution(1000))

